import{_ as t,o as i,c as s,ag as a}from"./chunks/framework.GolXoAlY.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"categories":["[[Clippings]]","[[Post]]"],"author":null,"url":["https://thedieline.com/oishiis-nikko-berry-tray-is-a-step-forward-but-is-it-enough/"],"tags":["Clippings","to-read"],"created":"2026-04-18T00:00:00.000Z","published":"2026-04-18T00:00:00.000Z","topics":null},"headers":[],"relativePath":"raw/sources/oishii-nikko-berry-tray-is-a-step-forward-but-is-it-enough-2026-04-18.md","filePath":"raw/sources/oishii-nikko-berry-tray-is-a-step-forward-but-is-it-enough-2026-04-18.md","lastUpdated":1776444206000}'),r={name:"raw/sources/oishii-nikko-berry-tray-is-a-step-forward-but-is-it-enough-2026-04-18.md"};function o(n,e,p,l,c,h){return i(),s("div",null,[...e[0]||(e[0]=[a('<p>Produce packaging has been stuck in the same plastic clamshell loop for decades, but <a href="https://oishii.com/" target="_blank" rel="noreferrer">Oishii’s</a> new Nikko Berry tray is one of the most considered attempts we’ve seen in working to break that pattern.</p><p>Oishii, the company behind what it bills as the world’s largest indoor vertical strawberry farm, has been selling its pesticide-free, non-GMO Japanese varietals at premium prices since 2018. Its newest berry, the Nikko, a Japanese strawberry, is its most affordable and widely distributed yet. The new packaging features a 7.5 oz cardboard tray sealed with a lightweight film, replacing the standard plastic clamshell that currently dominates the produce aisle.</p><p><img src="https://i0.wp.com/thedieline.com/wp-content/uploads/2026/04/Oishii-1150-scaled.jpg?resize=1638%2C2048&amp;quality=70&amp;ssl=1&amp;_jb=closest" alt=""></p><p><img src="https://i0.wp.com/thedieline.com/wp-content/uploads/2026/04/Oishii-40-scaled.jpg?resize=819%2C1024&amp;quality=70&amp;ssl=1&amp;_jb=closest" alt=""></p><p>The updated packaging is also designed to keep berries fresher for longer, directly addressing food waste at the consumer level. In tandem with the new packaging, Oishii launched its first-ever freshness guarantee, which is an open invitation for customers to reach out if their berries fall short of the brand’s standards. The guarantee shows confidence in Oishii’s growing process, where berries are non-GMO, pesticide-free, and harvested at peak ripeness inside smart farms engineered for consistent sweetness and quality year-round.</p><p>Sustainable packaging is one thing, but extending the viable life of the food inside adds a second, often overlooked dimension to the sustainability equation.</p><p><img src="https://i0.wp.com/thedieline.com/wp-content/uploads/2026/04/Oishii-1009-scaled.jpg?resize=1630%2C1304&amp;quality=70&amp;ssl=1&amp;_jb=custom" alt=""></p><p>The material engineering behind the switch is doing more than one job. As Rita Hudetz, CCO of Oishii, explains: “This new top-seal pack reduces plastic use by 80%+ compared to conventional strawberry packaging.” The construction is specific: a PET-based liner film sealed directly to SBS paperboard, with no adhesives or additives, and micro-perforations engineered to control oxygen and water vapor transmission rates.</p><p>Yes, the tray walks consumers through the steps of removing the film and fruit pad, separating the tray’s interior liner, and then discarding all three, and hopefully consumers will take the company’s lead and follow the instructions to disassemble and recycle what they can.</p><p><img src="https://i0.wp.com/thedieline.com/wp-content/uploads/2026/04/Oishii-40c-scaled.jpg?resize=1638%2C2048&amp;quality=70&amp;ssl=1&amp;_jb=closest" alt=""></p><p>The PET film liner, once separated, is not curbside recyclable in most U.S. municipalities, and the fruit pad goes straight to the trash, so the real-world end-of-life picture is a bit messier than the on-pack messaging suggests. That said, the team has mentioned that they’re actively exploring more sustainable alternatives.</p><p>That said, the 80% reduction in plastic is massive progress. By volume, eliminating most of the plastic from a produce container is a real material shift, and in a category where the clamshell has barely evolved in forty years, that’s something. The material shift is real, and the extension of freshness has genuine food waste implications.</p><p>We just have a long way to go until sustainable perfection.</p><p><img src="https://i0.wp.com/thedieline.com/wp-content/uploads/2026/04/Oishii-1185-scaled.jpg?resize=1638%2C2048&amp;quality=70&amp;ssl=1&amp;_jb=closest" alt=""></p><p><img src="https://i0.wp.com/thedieline.com/wp-content/uploads/2026/04/Oishii-1011-scaled.jpg?resize=1630%2C1304&amp;quality=70&amp;ssl=1&amp;_jb=custom" alt=""></p><p><img src="https://i0.wp.com/thedieline.com/wp-content/uploads/2026/04/Oishii-1160-scaled.jpg?resize=2720%2C3400&amp;quality=70&amp;ssl=1&amp;_jb=custom" alt=""></p>',16)])])}const u=t(r,[["render",o]]);export{m as __pageData,u as default};
